const comment = $input.first().json.body.comment || '';
const response = await fetch('http://aibrand-litellm:4000/v1/chat/completions', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer aibrand-litellm-key-2026'
  },
  body: JSON.stringify({
    model: 'qwen-turbo',
    messages: [{ role: 'user', content: '你是热情的客服。回复用户评论：' + comment }],
    max_tokens: 200
  })
});
const data = await response.json();
return { reply: data.choices[0].message.content, model: data.model, tokens: data.usage.total_tokens };
